# High-performance gRPC servicer
class HighThroughputServicer:
    def __init__(self):
        self.processing_queue = queue.Queue(maxsize=0)
        self.workers = []
        self.start_workers()
    
    def start_workers(self):
        num_workers = 64
        for _ in range(num_workers):
            worker = threading.Thread(target=self._worker, daemon=True)
            worker.start()
            self.workers.append(worker)
    
    def _worker(self):
        while True:
            try:
                task = self.processing_queue.get(timeout=1)
                if task is None:
                    break
                task()
            except queue.Empty:
                continue
    
    # Unary RPC - optimized for low latency
    def ProcessData(self, request, context):
        result = self._process_fast(request.data)
        return Response(result=result)
    
    # Server-side streaming RPC - high throughput data output
    def StreamFromServer(self, request, context):
        batch_size = 1000
        for i in range(100000):
            if context.is_active():
                yield StreamResponse(result=f"processed_{request.data}_{i}")
            else:
                break
    
    # Client-side streaming RPC - high throughput data ingestion
    def StreamToServer(self, request_iterator, context):
        count = 0
        batch = []
        batch_size = 1000
        
        for request in request_iterator:
            batch.append(request.data)
            count += 1
            
            if len(batch) >= batch_size:
                self._process_batch(batch)
                batch = []
        
        if batch:
            self._process_batch(batch)
        
        return Response(result=f"Processed {count} messages")
    
    # Bidirectional streaming RPC - real-time processing pipeline
    def StreamBidirectional(self, request_iterator, context):
        for request in request_iterator:
            if context.is_active():
                result = self._process_fast(request.data)
                yield StreamResponse(result=result)
            else:
                break
    
    def _process_fast(self, data):
        return f"processed_{data}_{time.time()}"
    
    def _process_batch(self, batch):
        return [self._process_fast(item) for item in batch]


