# Multi-port load distribution server
class MultiPortServer:
    def __init__(self, base_port=50051, num_ports=4):
        self.base_port = base_port
        self.num_ports = num_ports
        self.servers = []
    
    def start(self):
        for i in range(self.num_ports):
            port = self.base_port + i
            server = grpc.server(
                futures.ThreadPoolExecutor(max_workers=50),
                options=[
                    ('grpc.max_send_message_length', -1),
                    ('grpc.max_receive_message_length', -1),
                    ('grpc.max_concurrent_streams', 5000),
                    ('grpc.so_reuseport', 1),
                    ('grpc.http2.max_frame_size', 16777216),
                ]
            )
            
            servicer = HighThroughputServicer()
            # add_ServicerToServer(servicer, server)
            
            server.add_insecure_port(f'[::]:{port}')
            server.start()
            self.servers.append(server)
            print(f"Server started on port {port}")
        
        try:
            self.servers[0].wait_for_termination()
        except KeyboardInterrupt:
            self.stop()
    
    def stop(self):
        for server in self.servers:
            server.stop(0)


